'use strict';

/**
 * Sliding Window Rate Limiter for Express.js
 *
 * TRUE sliding window algorithm: for every request we drop all timestamps
 * older than `windowMs` relative to *now*, then count what's left. There is
 * no fixed bucket that resets on a clock boundary, so a client can never get
 * a burst "for free" by straddling a reset edge.
 *
 * --------------------------------------------------------------------------
 * NOTE ON req.ip BEHIND PROXIES
 * --------------------------------------------------------------------------
 * `req.ip` is derived from the socket's remote address UNLESS Express's
 * "trust proxy" setting is enabled. Behind a reverse proxy / load balancer
 * (Nginx, ELB, Cloudflare, etc.) every request will appear to come from the
 * proxy's IP, so all clients share one bucket and get rate-limited together.
 *
 * Enable trust proxy so Express reads the client IP from X-Forwarded-For:
 *
 *     app.set('trust proxy', 1);   // trust the first hop (your own proxy)
 *
 * Set this to the number of proxies in front of you, or a specific
 * subnet/predicate. Do NOT blindly use `true` on a public-facing app — a
 * client could spoof X-Forwarded-For and evade or poison the limiter.
 * --------------------------------------------------------------------------
 */

/**
 * @param {Object}  [options]
 * @param {number}  [options.windowMs=60000]          Window size in milliseconds.
 * @param {number}  [options.maxRequests=100]         Max requests allowed per window.
 * @param {number}  [options.cleanupIntervalMs=60000] How often to sweep idle IPs.
 * @param {(req) => string} [options.keyGenerator]    Override how a client is identified.
 * @returns {Function & { close: () => void }} Express middleware with a close() method.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    cleanupIntervalMs = 60000,
    keyGenerator = (req) => req.ip,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isFinite(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive number');
  }

  // Map<clientKey, number[]>  — array of request timestamps (ms epoch), ascending.
  const hits = new Map();

  /**
   * Drop every timestamp at or before `cutoff` from the front of the array.
   * Timestamps are stored in ascending order, so we only need to find the
   * first one that's still within the window.
   * @returns {number[]} the trimmed array (same reference, mutated)
   */
  function trim(timestamps, cutoff) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= cutoff) {
      i++;
    }
    if (i > 0) timestamps.splice(0, i);
    return timestamps;
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const cutoff = now - windowMs;
    const key = keyGenerator(req);

    let timestamps = hits.get(key);
    if (!timestamps) {
      timestamps = [];
      hits.set(key, timestamps);
    }

    // Slide the window: discard anything older than windowMs.
    trim(timestamps, cutoff);

    const used = timestamps.length;

    if (used >= maxRequests) {
      // Over the limit — reject. The window frees up when the OLDEST
      // surviving timestamp ages out, i.e. oldest + windowMs.
      const oldest = timestamps[0];
      const resetMs = oldest + windowMs;
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      res.setHeader('Retry-After', String(retryAfterSec));
      res.setHeader('X-RateLimit-Limit', String(maxRequests));
      res.setHeader('X-RateLimit-Remaining', '0');
      res.setHeader('X-RateLimit-Reset', String(Math.ceil(resetMs / 1000)));

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next()
    }

    // Under the limit — record this request and allow it.
    timestamps.push(now);

    const remaining = maxRequests - timestamps.length;
    // When this request's slot frees up (now + windowMs); also the point at
    // which the window has fully rolled over if no further requests arrive.
    const resetMs = now + windowMs;

    res.setHeader('X-RateLimit-Limit', String(maxRequests));
    res.setHeader('X-RateLimit-Remaining', String(remaining));
    res.setHeader('X-RateLimit-Reset', String(Math.ceil(resetMs / 1000)));

    next();
  };

  // ---- Memory management ---------------------------------------------------
  // Periodically remove IPs that have made no requests within the last window.
  const cleanup = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      trim(timestamps, cutoff);
      if (timestamps.length === 0) {
        hits.delete(key);
      }
    }
  }, cleanupIntervalMs);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanup.unref === 'function') {
    cleanup.unref();
  }

  // Allow callers to fully stop the timer (e.g. on graceful shutdown or
  // between tests) so it can't keep the event loop running.
  middleware.close = function close() {
    clearInterval(cleanup);
    hits.clear();
  };

  return middleware;
}

module.exports = createRateLimiter;
module.exports.createRateLimiter = createRateLimiter;
