const express = require('express');
const createRateLimiter = require('./rate-limiter');

const app = express();

// IMPORTANT behind a reverse proxy (Nginx, Cloudflare, ELB, ...):
// without this, req.ip is the proxy's IP and all clients share one bucket.
app.set('trust proxy', 1); // trust exactly one proxy hop

const limiter = createRateLimiter({
  windowMs: 60_000,  // 1 minute
  maxRequests: 100,  // 100 requests per IP per rolling minute
});

app.use(limiter);

app.get('/', (req, res) => res.json({ ok: true }));

const server = app.listen(3000, () => console.log('listening on :3000'));

// Graceful shutdown — stop the cleanup timer so the process can exit.
process.on('SIGTERM', () => {
  limiter.close();
  server.close();
});
