'use strict';

/**
 * Sliding Window Rate Limiter Middleware for Express.js
 *
 * Implements a TRUE sliding window algorithm — request timestamps are tracked
 * per-client and evaluated against a rolling lookback window anchored at the
 * current moment, not a fixed period that resets on a clock boundary.
 *
 * Proxy note:
 *   req.ip is derived from the socket address by default. If your app sits
 *   behind a reverse proxy (Nginx, load balancer, Cloudflare, etc.), Express
 *   will see the proxy's IP instead of the real client IP. Fix it with:
 *
 *     app.set('trust proxy', 1);          // trust one hop (e.g. Nginx on same host)
 *     app.set('trust proxy', 'loopback'); // trust only loopback proxies
 *     app.set('trust proxy', true);       // trust ALL X-Forwarded-For hops (risky)
 *
 *   With trust proxy enabled, Express reads the real IP from X-Forwarded-For.
 *   Never set trust proxy to `true` in production unless you control every
 *   network hop — a malicious client can spoof X-Forwarded-For and bypass
 *   the rate limit entirely.
 */

/**
 * @param {object} [options]
 * @param {number} [options.windowMs=60000]          - Rolling window size in ms
 * @param {number} [options.maxRequests=100]         - Max requests per window
 * @param {number} [options.cleanupIntervalMs=60000] - Stale-entry sweep frequency
 * @returns {{ middleware: Function, close: Function }}
 */
function createRateLimiter(options = {}) {
  const windowMs          = options.windowMs          ?? 60_000;
  const maxRequests       = options.maxRequests       ?? 100;
  const cleanupIntervalMs = options.cleanupIntervalMs ?? 60_000;

  if (typeof windowMs    !== 'number' || windowMs    <= 0)
    throw new TypeError('windowMs must be a positive number');
  if (typeof maxRequests !== 'number' || maxRequests <= 0)
    throw new TypeError('maxRequests must be a positive number');

  /**
   * Per-IP store: Map<ip: string, timestamps: number[]>
   *
   * Each value is a sorted-ascending array of request timestamps (epoch ms).
   * Entries are pruned on every request hit and swept by the cleanup interval.
   */
  const store = new Map();

  // ─── Sliding Window Core ────────────────────────────────────────────────

  /**
   * Remove timestamps that have scrolled out of the current window in-place.
   *
   * Because timestamps are appended in monotone order, all expired entries
   * are at the front of the array.  A binary search finds the first still-
   * valid index in O(log n); splice removes the stale prefix in O(n) — fast
   * in practice because windows stay small.
   *
   * @param {number[]} timestamps - Sorted ascending array
   * @param {number}   now        - Current epoch ms
   */
  function pruneExpired(timestamps, now) {
    const cutoff = now - windowMs;
    let lo = 0, hi = timestamps.length;
    while (lo < hi) {
      const mid = (lo + hi) >>> 1;
      if (timestamps[mid] <= cutoff) lo = mid + 1;
      else hi = mid;
    }
    if (lo > 0) timestamps.splice(0, lo);
  }

  // ─── Middleware ──────────────────────────────────────────────────────────

  function middleware(req, res, next) {
    const ip  = req.ip || req.socket?.remoteAddress || 'unknown';
    const now = Date.now();

    if (!store.has(ip)) store.set(ip, []);
    const timestamps = store.get(ip);

    // 1. Slide the window — discard timestamps older than windowMs from now
    pruneExpired(timestamps, now);

    const currentCount = timestamps.length;

    if (currentCount >= maxRequests) {
      // ── REJECTED ──────────────────────────────────────────────────────────
      // The earliest slot opens when the oldest in-window request expires:
      //   oldestTimestamp + windowMs
      // Retry-After = ceiling of that delta in whole seconds.
      const retryAfterMs  = Math.max(0, timestamps[0] + windowMs - now);
      const retryAfterSec = Math.ceil(retryAfterMs / 1000);

      res.setHeader('Retry-After', retryAfterSec);
      return res
        .status(429)
        .json({ error: 'Rate limit exceeded', retryAfter: retryAfterSec });
    }

    // ── ALLOWED ────────────────────────────────────────────────────────────
    timestamps.push(now);               // record this request in the window

    const remaining = maxRequests - timestamps.length;

    // Reset epoch = moment the oldest tracked timestamp leaves the window.
    // (timestamps[0] is `now` when this is the very first request, giving
    //  a reset time of now + windowMs — exactly right.)
    const resetSec = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.setHeader('X-RateLimit-Limit',     maxRequests);
    res.setHeader('X-RateLimit-Remaining', remaining);
    res.setHeader('X-RateLimit-Reset',     resetSec);   // epoch seconds

    next();
  }

  // ─── Background Cleanup ─────────────────────────────────────────────────
  // Sweep IPs whose entire window has expired so the store doesn't grow
  // unboundedly on servers with high client churn.

  const cleanupTimer = setInterval(() => {
    const now = Date.now();
    for (const [ip, timestamps] of store) {
      pruneExpired(timestamps, now);
      if (timestamps.length === 0) store.delete(ip);
    }
  }, cleanupIntervalMs);

  // Unreference so the timer doesn't prevent process exit on its own
  if (cleanupTimer.unref) cleanupTimer.unref();

  /** Call during graceful shutdown to clear the cleanup interval. */
  function close() {
    clearInterval(cleanupTimer);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
